  ('aboriginal-0a2fc18c-moex-00334', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '廠商的生產函數為q = LK，其中q為產量、L為勞動投入量、K則為資本投入量。則此生產函數 替代彈性的值為何？', '["0", "1", "2", "無窮大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00335', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '在完全競爭市場中，市場需求突然增加將導致：', '["廠商的長期利潤上升", "廠商的短期平均總成本上升", "廠商的長期平均總成本上升", "廠商的短期邊際收益上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00336', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '勞動獨買者所給付的工資率_______邊際勞動成本，並且______邊際勞動產值：', '["等於；等於", "低於；低於", "等於；低於", "低於；等於"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00337', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '政府考量民眾的生活負擔凍漲油價，要求國營企業以低於成本的價格供應汽油。請問政府此舉的 效果是：', '["汽油的交易量會減少", "導致民眾的生活水準下降", "帶來社會福利的無謂損失", "私人企業的汽油產量會上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00338', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '某人對X與Y的效用函數為U＝min{X,2Y}。若X與Y的價格分別為10與5且所得為100，則 最適消費數量為：', '["X＝8，Y＝4", "X＝4，Y＝8", "X＝6，Y＝3", "X＝10，Y＝5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00339', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', 'A廠商是一個追求利潤最大的獨占廠商，且面對需求函數Q＝24－2P，其中P為價格，Q為其產 量。A廠商的總成本函數為TC(Q)＝2＋3Q＋Q2。A廠商的最適價格及產量分別為：', '["11及2", "21/2及3", "10及4", "19/2及5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00340', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設政府對X商品課徵每單位2元的從量貨物稅（specificexcisetax），如果X商品的需求價格彈 性為完全彈性（perfectlyelastic），供給曲線是富有彈性（elastic），那麼X財的均衡價格將：', '["增加2元", "維持不變", "增加超過2元", "增加不到2元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00341', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設總合生產函數為Y=AK1/2L1/2，其中Y為總產出，A為總要素生產力（totalfactorproductivity） 表示當期的技術水準，K 為資本存量，L 為勞動量。若第一年資本存量為 6，勞動為 3，產出為 12；第2年資本存量為7，勞動為4，產出為14，則總要素生產力：', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
